            const newTime = time + 1;
            if (dist[node] === time && newTime < dist[node]) {
                dist[node] = newTime;
                pq.enqueue({ node: node, time: newTime });
            }
        }
    }

    return dist[n - 1] !== -1 ? dist[n - 1] : -1;
